class Solution:
  def solve(self, products) -> list:
    # TO DO: Write a SQL query to extract unique product categories in sorted order.
    query = "SELECT DISTINCT category FROM products GROUP BY category ORDER BY category ASC";
    import sqlite3
    conn = sqlite3.connect(':memory:')
    c = conn.cursor()
    c.executescript(query)
    rows = c.fetchall()
    return [row[0] for row in rows]
